#!/usr/bin/env bash
# Render servers/fhir-server-go/.env from bench.config.yaml — the single source of
# truth. compose.yaml reads ONLY this .env (never hard-codes), so changing a limit
# or pin in bench.config.yaml flows straight through. Re-run after editing config.
#   servers/fhir-server-go/render-env.sh
set -euo pipefail
HERE="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
ROOT="$(cd "$HERE/../.." && pwd)"
cfg() { "$ROOT/bin/cfg" "$1"; }

S=servers.fhir-server-go
OUT="$HERE/.env"

cat > "$OUT" <<EOF
# GENERATED by render-env.sh from bench.config.yaml — DO NOT EDIT BY HAND.
# Edit bench.config.yaml, then re-run render-env.sh.

# Identical resource envelope (fairness charter) — applied to every server.
SUT_CPUS=$(cfg limits.sut_cpus)
SUT_MEM=$(cfg limits.sut_mem)
DB_CPUS=$(cfg limits.db_cpus)
DB_MEM=$(cfg limits.db_mem)

# Source pin (latest main + unmerged PR #167).
FSG_REPO=$(cfg $S.repo)
FSG_REF=$(cfg $S.ref)
FSG_COMMIT=$(cfg $S.commit)
FSG_CONTEXT_SUBDIR=$(cfg $S.context_subdir)
FSG_BUILD_CONTEXT=$HERE/.src/$(cfg $S.context_subdir)

# Runtime contract.
FSG_DB_IMAGE=$(cfg $S.db_image)
FSG_PORT=$(cfg $S.port)
FSG_DB_PORT=$(cfg $S.db_port)
FSG_BASE_PATH=$(cfg $S.base_path)
FSG_HEALTH_PATH=$(cfg $S.health_path)
FSG_BASE_URL=http://localhost:$(cfg $S.port)$(cfg $S.base_path)
FSG_LOG_LEVEL=info
FSG_IG_PACKAGES=$(cfg $S.ig_packages)
FSG_VALIDATE_ON_WRITE=$(cfg $S.validate_on_write)
FSG_WRITE_TIMEOUT=$(cfg $S.write_timeout)

# Postgres credentials (match upstream compose defaults; not secrets — local-only DB).
FSG_DB_NAME=fhirdb
FSG_DB_USER=fhir
FSG_DB_PASSWORD=fhir
EOF

echo "==> wrote $OUT"
